import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
  CallToolRequestSchema,
  ListToolsRequestSchema,
} from "@modelcontextprotocol/sdk/types.js";
import {
  createZapierSdk,
  type ZapierSdk,
  type FunctionRegistryEntry,
} from "@zapier/zapier-sdk";
import { convertZodToMcpSchema } from "./utils/schema-converter.js";

import type { z } from "zod";

interface ZapierMcpServerOptions {
  debug?: boolean;
}

interface ZodSchemaWithShape extends z.ZodSchema {
  shape?: Record<string, z.ZodSchema>;
}

/**
 * Build a flat MCP-compatible JSON schema from inputParameters.
 * Simple-type params become required top-level properties; object-type params
 * have their properties flattened into the top level.
 */
function convertInputParametersToMcpSchema(
  inputParameters: Array<{ name: string; schema: z.ZodSchema }>,
): Record<string, unknown> {
  const properties: Record<string, unknown> = {};
  const required: string[] = [];

  for (const param of inputParameters) {
    let schema = param.schema;
    let isOptional = false;

    const optionalDef = (
      schema as unknown as {
        _zod?: { def?: { type?: string; innerType?: z.ZodSchema } };
      }
    )._zod?.def;

    if (optionalDef?.type === "optional" && optionalDef.innerType) {
      isOptional = true;
      schema = optionalDef.innerType;
    }

    const objectDef = (
      schema as unknown as { _zod?: { def?: { type?: string } } }
    )._zod?.def;

    if (objectDef?.type === "object") {
      const schemaWithShape = schema as ZodSchemaWithShape;
      if (schemaWithShape.shape) {
        for (const [key, fieldSchema] of Object.entries(
          schemaWithShape.shape,
        )) {
          properties[key] = convertZodToMcpSchema(fieldSchema);
          const fieldDef = (
            fieldSchema as unknown as {
              _zod?: { def?: { type?: string } };
            }
          )._zod?.def;
          if (
            !isOptional &&
            fieldDef?.type !== "optional" &&
            fieldDef?.type !== "nullable"
          ) {
            required.push(key);
          }
        }
      }
    } else {
      properties[param.name] = convertZodToMcpSchema(param.schema);
      if (!isOptional) {
        required.push(param.name);
      }
    }
  }

  const result: Record<string, unknown> = {
    type: "object",
    properties,
  };
  if (required.length > 0) {
    result.required = required;
  }
  return result;
}

/**
 * Reconstruct positional arguments for SDK invocation from a flat args object.
 * Mirrors the CLI's reconstructPositionalArgs for MCP tool calls.
 */
function reconstructMcpPositionalArgs(
  inputParameters: Array<{ name: string; schema: z.ZodSchema }>,
  flatArgs: Record<string, unknown>,
): unknown[] {
  const args: unknown[] = [];

  for (const param of inputParameters) {
    let schema = param.schema;

    const optionalDef = (
      schema as unknown as {
        _zod?: { def?: { type?: string; innerType?: z.ZodSchema } };
      }
    )._zod?.def;

    if (optionalDef?.type === "optional" && optionalDef.innerType) {
      schema = optionalDef.innerType;
    }

    const objectDef = (
      schema as unknown as { _zod?: { def?: { type?: string } } }
    )._zod?.def;

    if (objectDef?.type === "object") {
      const schemaWithShape = schema as ZodSchemaWithShape;
      if (schemaWithShape.shape) {
        const obj: Record<string, unknown> = {};
        let hasValues = false;
        for (const key of Object.keys(schemaWithShape.shape)) {
          if (key in flatArgs && flatArgs[key] !== undefined) {
            obj[key] = flatArgs[key];
            hasValues = true;
          }
        }
        args.push(hasValues ? obj : undefined);
      } else {
        args.push(undefined);
      }
    } else {
      args.push(flatArgs[param.name]);
    }
  }

  return args;
}

/**
 * Creates an MCP server that exposes Zapier SDK functions as MCP tools.
 *
 * The server automatically discovers all available SDK functions and converts
 * their Zod schemas to MCP-compatible JSON schemas. It handles tool execution
 * by validating inputs and calling the appropriate SDK functions.
 *
 * @param options - Configuration options for the MCP server
 * @param options.debug - Enable debug logging for detailed error information
 * @returns An MCP server instance configured to expose Zapier SDK tools
 *
 * @example
 * ```typescript
 * const server = createZapierMcpServer({ debug: true });
 * const transport = new StdioServerTransport();
 * await server.connect(transport);
 * ```
 */
function createZapierMcpServer({ debug = false }: ZapierMcpServerOptions = {}) {
  // Create Zapier SDK instance
  const zapierSdk: ZapierSdk = createZapierSdk({
    debug,
    eventEmission: { callContext: "mcp" },
  });

  // Create MCP server
  const server = new Server(
    {
      name: "zapier-sdk",
      version: "1.0.0",
    },
    {
      capabilities: {
        tools: {},
      },
    },
  );

  // Register list_tools handler - dynamically list all SDK functions as tools
  server.setRequestHandler(ListToolsRequestSchema, async () => {
    const tools = zapierSdk
      .getRegistry({ package: "mcp" })
      .functions.map((functionInfo: FunctionRegistryEntry) => {
        const toolName = functionInfo.name
          .replace(/([A-Z])/g, "-$1")
          .toLowerCase();

        const description =
          functionInfo.description ||
          functionInfo.inputSchema?.description ||
          `Execute ${functionInfo.name}`;

        if (functionInfo.inputSchema) {
          return {
            name: toolName,
            description,
            inputSchema: convertZodToMcpSchema(functionInfo.inputSchema),
          };
        }

        // Build a synthetic MCP schema from inputParameters
        return {
          name: toolName,
          description,
          inputSchema: convertInputParametersToMcpSchema(
            functionInfo.inputParameters!,
          ),
        };
      });

    return { tools };
  });

  // Register call_tool handler - execute SDK functions
  server.setRequestHandler(CallToolRequestSchema, async (request) => {
    const { name, arguments: args } = request.params;

    // Convert kebab-case tool name back to camelCase function name
    const functionName = name.replace(/-([a-z])/g, (_, letter) =>
      letter.toUpperCase(),
    );

    // Find the function info
    const functionInfo: FunctionRegistryEntry | undefined = zapierSdk
      .getRegistry({ package: "mcp" })
      .functions.find(
        (info: FunctionRegistryEntry) => info.name === functionName,
      );

    if (!functionInfo) {
      const availableTools = zapierSdk
        .getRegistry({ package: "mcp" })
        .functions.map((info) =>
          info.name.replace(/([A-Z])/g, "-$1").toLowerCase(),
        )
        .join(", ");
      throw new Error(
        `Unknown tool: ${name}. Available tools: ${availableTools}`,
      );
    }

    try {
      let result: unknown;

      if (functionInfo.inputSchema) {
        // Standard single-object-parameter function
        const validatedArgs = functionInfo.inputSchema.parse(args || {});
        const sdkFn = (
          zapierSdk as unknown as Record<
            string,
            (...args: unknown[]) => Promise<unknown>
          >
        )[functionInfo.name];
        result = await sdkFn(validatedArgs);
      } else if (functionInfo.inputParameters) {
        // Multi-parameter function (e.g. fetch) — reconstruct positional args from flat object
        const flatArgs = (args || {}) as Record<string, unknown>;
        const positionalArgs = reconstructMcpPositionalArgs(
          functionInfo.inputParameters,
          flatArgs,
        );
        const sdkFn = (
          zapierSdk as unknown as Record<
            string,
            (...args: unknown[]) => Promise<unknown>
          >
        )[functionInfo.name];
        result = await sdkFn(...positionalArgs);
      } else {
        const sdkFn = (
          zapierSdk as unknown as Record<
            string,
            (...args: unknown[]) => Promise<unknown>
          >
        )[functionInfo.name];
        result = await sdkFn();
      }

      return {
        content: [
          {
            type: "text",
            text: JSON.stringify(result, null, 2),
          },
        ],
      };
    } catch (error) {
      if (debug) {
        console.error(
          `Error executing function '${functionInfo.name}' (tool: ${name}):`,
          error,
        );
      }

      let errorMessage: string;
      let isValidationError = false;

      if (error instanceof Error) {
        // Check if it's a Zod validation error
        if (error.name === "ZodError") {
          isValidationError = true;
          errorMessage = `Validation error for ${functionInfo.name}: ${error.message}`;
        } else {
          errorMessage = `Error in ${functionInfo.name}: ${error.message}`;
        }
      } else {
        errorMessage = `Unexpected error in ${functionInfo.name}: ${String(error)}`;
      }

      const errorSchema = functionInfo.inputSchema
        ? convertZodToMcpSchema(functionInfo.inputSchema)
        : functionInfo.inputParameters
          ? convertInputParametersToMcpSchema(functionInfo.inputParameters)
          : {};

      return {
        content: [
          {
            type: "text",
            text: isValidationError
              ? `${errorMessage}\n\nExpected input format:\n${JSON.stringify(errorSchema, null, 2)}`
              : errorMessage,
          },
        ],
        isError: true,
      };
    }
  });

  return server;
}

/**
 * Starts an MCP server with stdio transport for CLI usage.
 *
 * This is the main entry point when running the MCP server from the command line.
 * It creates the server and connects it using stdio transport for communication
 * with MCP clients like Claude Code.
 *
 * @param options - Configuration options for the MCP server
 * @param options.debug - Enable debug logging for detailed error information
 *
 * @example
 * ```typescript
 * // Start server with debug logging
 * await startMcpServer({ debug: true });
 * ```
 */
async function startMcpServer(
  options: ZapierMcpServerOptions = {},
): Promise<void> {
  const server = createZapierMcpServer(options);
  const transport = new StdioServerTransport();

  return new Promise<void>((resolve) => {
    let isShuttingDown = false;

    const cleanup = async () => {
      if (isShuttingDown) return;
      isShuttingDown = true;

      try {
        await server.close();
      } finally {
        resolve();
      }
    };

    // Handle clean shutdown when client closes connection
    server.onclose = () => {
      cleanup();
    };

    // Handle termination signals (Ctrl+C, kill, etc.)
    // Using process.once() to prevent handler accumulation
    process.once("SIGINT", cleanup);
    process.once("SIGTERM", cleanup);

    server.connect(transport).catch((error) => {
      console.error("Failed to start MCP server:", error);
      process.exit(1);
    });
  });
}

export { createZapierMcpServer, startMcpServer };
