/**
 * A robust schema converter that handles conversion from Zod schemas to JSON Schema format:
 *
 * **Core Types:**
 * - ✅ Objects, arrays, strings, numbers, booleans
 * - ✅ Enums, unions, intersections, literals
 * - ✅ Optional and nullable fields
 * - ✅ Records and dates
 * - ✅ Nested schemas and complex types
 *
 * **Additional Types:**
 * - ✅ Any, unknown, bigint, null, undefined, void, NaN
 * - ✅ Default values and catch handlers (unwrapped to inner type)
 * - ✅ Graceful fallback for unsupported types
 */

import type { z } from "zod";

interface McpSchema {
  type?: string | string[];
  properties?: Record<string, McpSchema>;
  required?: string[];
  description?: string;
  items?: McpSchema;
  enum?: unknown[];
  anyOf?: McpSchema[];
  oneOf?: McpSchema[];
  allOf?: McpSchema[];
  additionalProperties?: McpSchema | boolean;
  format?: string;
}

// Zod internal definition structure
interface ZodDef {
  type: string; // e.g., "string", "number", "object", "optional", etc.
  element?: z.ZodSchema; // For arrays
  innerType?: z.ZodSchema; // For optional, nullable, default, catch
  entries?: Record<string, string>; // For enums
  values?: unknown[]; // For literals
  options?: z.ZodSchema[]; // For unions
  left?: z.ZodSchema; // For intersections
  right?: z.ZodSchema; // For intersections
  keyType?: z.ZodSchema; // For records (key type)
  valueType?: z.ZodSchema; // For records (value type)
  shape?: Record<string, z.ZodSchema>; // For objects (function in some cases)
}

// Zod schema with description (description is on the schema, not the def)
interface ZodSchemaWithDescription extends z.ZodSchema {
  description?: string;
}

interface ZodSchemaWithShape extends z.ZodSchema {
  shape?: Record<string, z.ZodSchema>;
}

/**
 * Gets the Zod def from a schema, with fallback for edge cases
 */
function getZodDef(schema: z.ZodSchema): ZodDef | undefined {
  const schemaAny = schema as unknown as { _zod?: { def?: ZodDef } };
  return schemaAny._zod?.def;
}

/**
 * Gets the description from a Zod schema (description is on the schema object, not the def)
 */
function getDescription(schema?: z.ZodSchema): string | undefined {
  if (!schema) return undefined;
  return (schema as ZodSchemaWithDescription).description;
}

/**
 * Converts a Zod schema to MCP-compatible JSON Schema format.
 *
 * This function handles the conversion of Zod validation schemas (used internally
 * by the Zapier SDK) to JSON Schema format required by the MCP protocol. It supports
 * most common Zod types including objects, arrays, primitives, enums, unions, and more.
 *
 * @param zodSchema - The Zod schema to convert
 * @returns An MCP-compatible JSON Schema object
 *
 * @example
 * ```typescript
 * import { z } from "zod";
 *
 * const userSchema = z.object({
 *   name: z.string(),
 *   age: z.number().optional(),
 *   email: z.string().email()
 * });
 *
 * const mcpSchema = convertZodToMcpSchema(userSchema);
 * // Result: { type: "object", properties: { ... }, required: ["name", "email"] }
 * ```
 */
function convertZodToMcpSchema(zodSchema: z.ZodSchema): McpSchema {
  const def = getZodDef(zodSchema);
  if (!def) {
    // Fallback for schemas without _zod.def (e.g., custom or invalid schemas)
    return {
      type: "string",
      description: "Unsupported schema type",
    };
  }
  return convertZodType(def, zodSchema);
}

/**
 * Internal function that recursively converts Zod type definitions to MCP schema format.
 *
 * This function handles the actual conversion logic for different Zod types by examining
 * the internal type definition and converting it to the appropriate JSON Schema structure.
 *
 * @param def - The Zod internal definition object
 * @param schema - The original Zod schema (used for accessing shape in objects)
 * @returns An MCP-compatible JSON Schema object
 * @internal
 */
function convertZodType(def: ZodDef, schema?: z.ZodSchema): McpSchema {
  const description = getDescription(schema);

  // Handle object
  if (def.type === "object" && schema) {
    const schemaWithShape = schema as ZodSchemaWithShape;
    const properties: Record<string, McpSchema> = {};
    const required: string[] = [];

    if (schemaWithShape.shape) {
      for (const [key, value] of Object.entries(schemaWithShape.shape)) {
        const fieldDef = getZodDef(value);
        if (fieldDef) {
          properties[key] = convertZodType(fieldDef, value);

          // Check if field is required (not optional or nullable)
          if (fieldDef.type !== "optional" && fieldDef.type !== "nullable") {
            required.push(key);
          }
        }
      }
    }

    const result: McpSchema = {
      type: "object",
      properties,
    };

    if (description) result.description = description;
    if (required.length > 0) result.required = required;

    return result;
  }

  // Handle string
  if (def.type === "string") {
    const result: McpSchema = { type: "string" };
    if (description) result.description = description;
    return result;
  }

  // Handle number
  if (def.type === "number") {
    const result: McpSchema = { type: "number" };
    if (description) result.description = description;
    return result;
  }

  // Handle boolean
  if (def.type === "boolean") {
    const result: McpSchema = { type: "boolean" };
    if (description) result.description = description;
    return result;
  }

  // Handle array
  if (def.type === "array" && def.element) {
    const elementDef = getZodDef(def.element);
    const result: McpSchema = {
      type: "array",
      items: elementDef
        ? convertZodType(elementDef, def.element)
        : { type: "string" },
    };
    if (description) result.description = description;
    return result;
  }

  // Handle optional
  if (def.type === "optional" && def.innerType) {
    const innerDef = getZodDef(def.innerType);
    if (innerDef) {
      return convertZodType(innerDef, def.innerType);
    }
  }

  // Handle nullable
  if (def.type === "nullable" && def.innerType) {
    const innerDef = getZodDef(def.innerType);
    if (innerDef) {
      const innerSchema = convertZodType(innerDef, def.innerType);
      if (innerSchema.type !== undefined) {
        return {
          ...innerSchema,
          type: Array.isArray(innerSchema.type)
            ? [...innerSchema.type, "null"]
            : [innerSchema.type, "null"],
        };
      }
      return {
        anyOf: [innerSchema, { type: "null" }],
      };
    }
  }

  // Handle enum
  if (def.type === "enum" && def.entries) {
    const result: McpSchema = {
      type: "string",
      enum: Object.keys(def.entries),
    };
    if (description) result.description = description;
    return result;
  }

  // Handle union
  if (def.type === "union" && def.options) {
    const result: McpSchema = {
      oneOf: def.options
        .map((option) => {
          const optionDef = getZodDef(option);
          return optionDef ? convertZodType(optionDef, option) : null;
        })
        .filter((s): s is McpSchema => s !== null),
    };
    if (description) result.description = description;
    return result;
  }

  // Handle intersection
  if (def.type === "intersection" && def.left && def.right) {
    const leftDef = getZodDef(def.left);
    const rightDef = getZodDef(def.right);
    const result: McpSchema = {
      allOf: [
        leftDef ? convertZodType(leftDef, def.left) : { type: "string" },
        rightDef ? convertZodType(rightDef, def.right) : { type: "string" },
      ],
    };
    if (description) result.description = description;
    return result;
  }

  // Handle literal
  if (def.type === "literal" && def.values && def.values.length > 0) {
    const value = def.values[0];
    const result: McpSchema = {
      type: typeof value as "string" | "number" | "boolean",
      enum: [value],
    };
    if (description) result.description = description;
    return result;
  }

  // Handle record
  if (def.type === "record") {
    let additionalProperties: McpSchema | boolean = true;
    if (def.valueType) {
      const valueDef = getZodDef(def.valueType);
      if (valueDef) {
        additionalProperties = convertZodType(valueDef, def.valueType);
      }
    }
    const result: McpSchema = {
      type: "object",
      additionalProperties,
    };
    if (description) result.description = description;
    return result;
  }

  // Handle any
  if (def.type === "any") {
    const result: McpSchema = {};
    if (description) result.description = description;
    return result;
  }

  // Handle unknown
  if (def.type === "unknown") {
    const result: McpSchema = {};
    if (description) result.description = description;
    return result;
  }

  // Handle date
  if (def.type === "date") {
    return {
      type: "string",
      format: "date-time",
      description: description || "ISO 8601 date-time string",
    };
  }

  // Handle bigint
  if (def.type === "bigint") {
    return {
      type: "string",
      description: description || "BigInt as string",
    };
  }

  // Handle undefined
  if (def.type === "undefined") {
    return {
      type: "null",
      description: description || "Undefined value",
    };
  }

  // Handle null
  if (def.type === "null") {
    return {
      type: "null",
      description: description || "Null value",
    };
  }

  // Handle void
  if (def.type === "void") {
    return {
      type: "null",
      description: description || "Void (null) value",
    };
  }

  // Handle nan
  if (def.type === "nan") {
    return {
      type: "number",
      description: description || "Not-a-Number value",
    };
  }

  // Handle default
  if (def.type === "default" && def.innerType) {
    const innerDef = getZodDef(def.innerType);
    if (innerDef) {
      return convertZodType(innerDef, def.innerType);
    }
  }

  // Handle catch (with fallback value)
  if (def.type === "catch" && def.innerType) {
    const innerDef = getZodDef(def.innerType);
    if (innerDef) {
      return convertZodType(innerDef, def.innerType);
    }
  }

  // Fallback for unhandled types
  console.warn(
    `Unhandled Zod type: ${def.type}. Please consider adding support for this type.`,
  );
  return {
    type: "string",
    description: description || `Unsupported type: ${def.type}`,
  };
}

export { convertZodToMcpSchema };
